// WRONG: Captive dependency — Singleton inject Scoped
public class EmailNotificationService(AppDbContext db) // db là Scoped!
    : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken ct)
    {
        // db bị capture từ lúc Singleton khởi tạo → không bao giờ dispose → LEAK
        while (!ct.IsCancellationRequested) { await DoWorkAsync(db, ct); }
    }
}

// RIGHT: IServiceScopeFactory trong Singleton
public class EmailNotificationService(IServiceScopeFactory scopeFactory)
    : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromMinutes(1));
        while (await timer.WaitForNextTickAsync(ct))
        {
            await using var scope = scopeFactory.CreateAsyncScope();
            var db = scope.ServiceProvider.GetRequiredService<AppDbContext>();
            await SendPendingEmailsAsync(db, ct);
        } // scope dispose → db dispose sau mỗi iteration
    }
}

// Phát hiện captive dependency tại startup:
builder.Host.UseDefaultServiceProvider(opt =>
{
    opt.ValidateScopes = true;      // phát hiện captive dependency
    opt.ValidateOnBuild = true;     // verify tất cả registered services có thể resolve
});
